results.ai_instructions:
{
  "format": {
    "structure": {
      "type": "bubblechart",
      "color": "gray",
      "imageWidth": "100%",
      "imageHeight": "100%",
      "visible": true
    },
    "data_format": {
      "info": {
        "data": [
          {
            "x": "numeric value",
            "y": "numeric value",
            "size": "numeric value (30-80)",
            "label": "string",
            "color": "hex color code"
          }
        ],
        "xLabel": "string",
        "yLabel": "string"
      }
    }
  },
  "validation": {
    "required_fields": [
      "label",
      "info.data",
      "info.xLabel",
      "info.yLabel"
    ],
    "data_points": {
      "min": 1,
      "max": 20
    },
    "values": {
      "size": {
        "min": 30,
        "max": 80
      }
    }
  }
}

{
  "format": {
    "structure": {
      "type": "fulltext",
      "color": "#D2691E",
      "imageWidth": "100%",
      "imageHeight": "100%",
      "visible": true
    },
    "data_format": {
      "info": {
        "sections": [
          {
            "type": "title",
            "format": "[FANCY | font-size: 4.5em; color: #2c3e50; text-align: center]",
            "required": true
          },
          {
            "type": "header_image",
            "format": "![Header|height: 200px; object-fit: cover; object-position: center]",
            "required": true
          },
          {
            "type": "introduction",
            "format": "## Introduction\n\n[SECTION | background-color:#FFFBE6; color:#000]",
            "required": true
          },
          {
            "type": "quote",
            "format": "[QUOTE | Cited=Author Name]",
            "required": false
          },
          {
            "type": "key_points",
            "format": "## Key Points\n\n1. ",
            "required": true
          },
          {
            "type": "additional_section",
            "format": "[SECTION | background-color:#E7F7F7; color:#111]",
            "required": false
          }
        ]
      }
    }
  },
  "validation": {
    "required_fields": [
      "label",
      "info",
      "type",
      "color"
    ],
    "sections": {
      "min": 3,
      "max": 6
    },
    "content": {
      "min_length": 100,
      "max_length": 5000
    }
  }
}

{
